mapper.select:
SELECT b.seq, c.name AS categoryName, b.author, b.title, b.view_count AS viewCount, b.created_at AS createdAt, b.updated_at AS updatedAt, EXISTS( SELECT 1 FROM attachment a WHERE a.board_seq = b.seq ) AS hasAttachment FROM board b INNER JOIN category c ON c.id = b.category_id
AND ( b.title LIKE CONCAT('%', #{keyword}, '%') OR b.content LIKE CONCAT('%', #{keyword}, '%') OR b.author LIKE CONCAT('%', #{keyword}, '%') )
AND b.category_id = #{categoryId}
AND b.created_at >= #{startDate}
AND b.created_at <= #{endDate}
ORDER BY b.created_at DESC

SELECT EXISTS(
    SELECT 1 FROM board WHERE seq = #{seq}
    )

mapper.update:
UPDATE board
SET view_count = view_count + 1
WHERE seq = #{seq}

UPDATE board
SET category_id = #{categoryId},
    title        = #{title},
    content      = #{content},
    updated_at   = #{updatedAt}
WHERE seq = #{seq}
